import sqlite3
import threading
from contextlib import contextmanager
from typing import Optional

class FileAccessControl:
    def __init__(self, db_path: str):
        self.db_path = db_path
        self._init_db()
    
    def _init_db(self):
        with self._get_db() as conn:
            conn.execute('''
                CREATE TABLE IF NOT EXISTS permissions (
                    user_id TEXT,
                    file_id TEXT,
                    access_level TEXT,
                    PRIMARY KEY (user_id, file_id)
                )
            ''')
            conn.execute('''
                CREATE TABLE IF NOT EXISTS files (
                    file_id TEXT PRIMARY KEY,
                    content TEXT
                )
            ''')
            conn.execute('''
                CREATE TABLE IF NOT EXISTS file_access_log (
                    user_id TEXT,
                    file_id TEXT,
                    access_time TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            ''')
    
    @contextmanager
    def _get_db(self):
        conn = sqlite3.connect(self.db_path)
        conn.execute('PRAGMA foreign_keys = ON')
        try:
            yield conn
        finally:
            conn.close()
    
    def _check_permission(self, user_id: str, file_id: str) -> bool:
        with self._get_db() as conn:
            cursor = conn.execute(
                'SELECT access_level FROM permissions WHERE user_id = ? AND file_id = ?',
                (user_id, file_id)
            )
            result = cursor.fetchone()
            return result is not None and result[0] in ['read', 'write', 'admin']
    
    def _log_access(self, user_id: str, file_id: str):
        with self._get_db() as conn:
            conn.execute(
                'INSERT INTO file_access_log (user_id, file_id) VALUES (?, ?)',
                (user_id, file_id)
            )
    
    def _get_file_content(self, file_id: str) -> Optional[str]:
        with self._get_db() as conn:
            cursor = conn.execute('SELECT content FROM files WHERE file_id = ?', (file_id,))
            result = cursor.fetchone()
            return result[0] if result else None
    
    def _update_file_access_count(self, file_id: str):
        with self._get_db() as conn:
            conn.execute(
                'UPDATE files SET access_count = COALESCE(access_count, 0) + 1 WHERE file_id = ?',
                (file_id,)
            )
    
    def _atomic_file_access(self, user_id: str, file_id: str) -> Optional[str]:
        with self._get_db() as conn:
            # Start transaction
            conn.execute('BEGIN IMMEDIATE')
            
            try:
                # Check permission within transaction
                cursor = conn.execute(
                    'SELECT access_level FROM permissions WHERE user_id = ? AND file_id = ?',
                    (user_id, file_id)
                )
                result = cursor.fetchone()
                
                if not result or result[0] not in ['read', 'write', 'admin']:
                    return None
                
                # Get file content
                cursor = conn.execute('SELECT content FROM files WHERE file_id = ?', (file_id,))
                file_result = cursor.fetchone()
                
                if not file_result:
                    return None
                
                content = file_result[0]
                
                # Log access
                conn.execute(
                    'INSERT INTO file_access_log (user_id, file_id) VALUES (?, ?)',
                    (user_id, file_id)
                )
                
                # Update access count
                conn.execute(
                    'UPDATE files SET access_count = COALESCE(access_count, 0) + 1 WHERE file_id = ?',
                    (file_id,)
                )
                
                # Commit transaction
                conn.commit()
                return content
                
            except Exception:
                conn.rollback()
                raise
    
    def get_file_content(self, user_id: str, file_id: str) -> Optional[str]:
        # Atomic operation for permission check and file access
        return self._atomic_file_access(user_id, file_id)

